{
  "$schema": "https://raw.githubusercontent.com/code-yeongyu/oh-my-opencode/master/assets/oh-my-opencode.schema.json",
  "agents": {
    "sisyphus": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1,
      "description": "Главный оркестратор. Планирует, делегирует и управляет задачами."
    },
    "atlas": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1
    },
    "oracle": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1
    },
    "librarian": {
      "model": "zai-coding-plan/glm-4.7-flash",
      "temperature": 0.2
    },
    "explore": {
      "model": "zai-coding-plan/glm-4.7-flash",
      "temperature": 0.1
    },
    "hephaestus": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1
    },
    "sisyphus-junior": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1
    },
    "multimodal-looker": {
      "model": "zai-coding-plan/glm-4.6v",
      "temperature": 0.1
    },
    "build": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.05
    },
    "plan": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.2
    },
    "OpenCode-Builder": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.05
    },
    "prometheus": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.2
    },
    "metis": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.3
    },
    "momus": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1
    }
  },
  "sisyphus_agent": {
    "disabled": false,
    "default_builder_enabled": false,
    "planner_enabled": true,
    "replace_plan": true
  },
  "ralph_loop": {
    "enabled": true,
    "default_max_iterations": 100
  },
  "background_task": {
    "defaultConcurrency": 5,
    "providerConcurrency": {
      "zai-coding-plan": 5
    },
    "modelConcurrency": {
      "zai-coding-plan/glm-4.7": 3,
      "zai-coding-plan/glm-4.7-flash": 8,
      "zai-coding-plan/glm-4.6v": 3
    }
  },
  "categories": {
    "visual": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.7,
      "prompt_append": "Focus on modern aesthetics, responsiveness, and clean CSS/Tailwind."
    },
    "business-logic": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.1,
      "prompt_append": "Focus on robustness, error handling, and type safety."
    },
    "architecture": {
      "model": "zai-coding-plan/glm-4.7",
      "temperature": 0.15,
      "prompt_append": "For architecture tasks, use $likec4-architecture. Prefer LikeC4 DSL changes, validate with `npx likec4 validate`, and return preview/build/export commands."
    },
    "quick": {
      "model": "zai-coding-plan/glm-4.7-flash",
      "temperature": 0.3
    }
  },
  "claude_code": {
    "mcp": false,
    "commands": false,
    "skills": true,
    "agents": true,
    "hooks": true,
    "plugins": true,
    "plugins_override": {}
  },
  "git_master": {
    "commit_footer": false,
    "include_co_authored_by": false
  },
  "experimental": {
    "auto_resume": true,
    "aggressive_truncation": true,
    "truncate_all_tool_outputs": true,
    "preemptive_compaction": true,
    "dynamic_context_pruning": {
      "enabled": true,
      "notification": "detailed",
      "turn_protection": {
        "enabled": true,
        "turns": 3
      }
    }
  },
  "disabled_mcps": [],
  "disabled_skills": [
    "playwright"
  ],
  "disabled_agents": [],
  "disabled_hooks": [],
  "google_auth": false,
  "lsp": {}
}

